#include<bits/stdc++.h>
using namespace std;
const long long N=5010,M=100010;
long long head[N],now[N],tot=1,d[N],n,m,s,t,res;
bool vis[N];
struct edge
{
    long long to,flow,cost,nxt;
}e[M];
void add1(long long u,long long v,long long w,long long c)
{
    e[++tot]={v,w,c,head[u]};
    head[u]=tot;
}
void add(long long u,long long v,long long w,long long c)
{
    add1(u,v,w,c);
    add1(v,u,0,-c);
}
bool spfa()
{
    memset(d,0x3f,sizeof(d));
    long long inf=d[0];
    d[s]=0;
    queue<long long> q;
    q.push(s);
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        vis[t]=false;
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,val=e[i].flow,cost=e[i].cost;
            if(val&&d[v]>d[t]+cost)
            {
                d[v]=d[t]+cost;
                if(!vis[v])
                {
                    vis[v]=true;
                    q.push(v);
                }
            }
        }
    }
    return d[t]<inf;
}
long long dfs(long long x,long long flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    vis[x]=true;
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,cost=e[i].cost;
        if(!vis[v]&&d[v]==d[x]+cost&&e[i].flow)
        {
            long long tmp=dfs(v,min(flow,e[i].flow));
            e[i].flow-=tmp;
            e[i^1].flow+=tmp;
            sum+=tmp;
            res+=tmp*cost;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    vis[x]=false;
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(spfa())
    {
        memcpy(now,head,sizeof(head));
        ans+=dfs(s,2e9);
    }
    return ans;
}
int main()
{
    scanf("%lld%lld%lld%lld",&n,&m,&s,&t);
    for(long long i=1;i<=m;i++)
    {
        long long u,v,w,c;
        scanf("%lld%lld%lld%lld",&u,&v,&w,&c);
        add(u,v,w,c);
    }
    printf("%lld ",dinic());
    printf("%lld",res);
    return 0;
}
